import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.mem0.ai/api-reference";
const PLACEHOLDER_VALUE = "m0-CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocal";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Mem0 API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:mem0",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const mem0Firewall = {",
    '  name: "mem0",',
    '  description: "Mem0",',
    "  placeholders: {",
    `    MEM0_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.mem0.ai",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Token ${{ secrets.MEM0_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Mem0 firewall config...");
  const ts = generateTypeScript();
  writeOutput("mem0", ts, import.meta.dirname);
}
